const mkResponse = $input.first().json;
const body = $('Webhook Trigger').first().json.body || {};
const endereco = (body.endereco || '').toLowerCase();

// Normalizar texto removendo acentos
function norm(str) {
  return (str || '').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ').trim();
}

const endNorm = norm(endereco);
const partes = endNorm.split(/[,\-\s]+/).filter(p => p.length > 2);

// Extrair lista de endereços do MK
let lista = [];
try {
  const data = mkResponse.ListaEnderecos || mkResponse.EstruturaEnderecos
    || mkResponse.estrutura_enderecos || mkResponse.Enderecos || mkResponse;
  if (Array.isArray(data)) {
    lista = data;
  } else if (data && typeof data === 'object') {
    lista = Object.values(data).flat().filter(v => typeof v === 'object');
  }
} catch (e) {}

const cidadesMK = [...new Set(lista.map(r => r.cidade).filter(Boolean))];
const bairrosMK = [...new Set(lista.map(r => r.bairro).filter(Boolean))];

// Buscar match de CIDADE
let cidadeMatch = null;
for (const cidade of cidadesMK) {
  const cidNorm = norm(cidade);
  if (cidNorm && (endNorm.includes(cidNorm) || partes.some(p => cidNorm.includes(p) && p.length > 3))) {
    cidadeMatch = cidade;
    break;
  }
}

// Buscar match de BAIRRO
let bairroMatch = null;
const bairrosFiltrados = cidadeMatch
  ? lista.filter(r => r.cidade === cidadeMatch).map(r => r.bairro).filter(Boolean)
  : bairrosMK;

for (const bairro of [...new Set(bairrosFiltrados)]) {
  const bNorm = norm(bairro);
  if (bNorm && bNorm.length > 2 && (endNorm.includes(bNorm) || partes.some(p => bNorm.includes(p) && p.length > 3))) {
    bairroMatch = bairro;
    break;
  }
}

const temCobertura = !!(cidadeMatch);

return [{
  json: {
    success: true,
    data: {
      tem_cobertura: temCobertura,
      cidade_encontrada: cidadeMatch || null,
      bairro_encontrado: bairroMatch || null,
      endereco_consultado: body.endereco || '',
      total_cidades_atendidas: cidadesMK.length,
      cidades_atendidas: cidadesMK.slice(0, 20),
    },
    endpoint: 'WSMKListaEstruturaEnderecos',
    session_id: body.session_id || null
  }
}];
